import{_ as a,c as o,o as n,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"FAQ: Solución de Problemas | opencode-md-table-formatter","description":"Aprende a solucionar problemas comunes del plugin opencode-md-table-formatter. Identifica rápidamente problemas de formato de tablas y soluciona configuración, estructura y alineación.","frontmatter":{"title":"FAQ: Solución de Problemas | opencode-md-table-formatter","sidebarTitle":"¿Qué hacer si tienes problemas","subtitle":"FAQ: Solución de Problemas | opencode-md-table-formatter","description":"Aprende a solucionar problemas comunes del plugin opencode-md-table-formatter. Identifica rápidamente problemas de formato de tablas y soluciona configuración, estructura y alineación.","order":3},"headers":[],"relativePath":"es/franlol/opencode-md-table-formatter/faq/index.md","filePath":"es/franlol/opencode-md-table-formatter/faq/index.md"}'),s={name:"es/franlol/opencode-md-table-formatter/faq/index.md"};function r(t,e,l,d,c,u){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h1><h2 id="resumen-del-capitulo" tabindex="-1">Resumen del Capítulo <a class="header-anchor" href="#resumen-del-capitulo" aria-label="Permalink to &quot;Resumen del Capítulo&quot;">​</a></h2><p>Este capítulo cubre las preguntas frecuentes y los métodos de solución de problemas del plugin opencode-md-table-formatter, ayudándote a identificar y resolver rápidamente varios problemas que encuentres durante el proceso de formato de tablas.</p><hr><h2 id="navegacion-de-subpaginas" tabindex="-1">Navegación de Subpáginas <a class="header-anchor" href="#navegacion-de-subpaginas" aria-label="Permalink to &quot;Navegación de Subpáginas&quot;">​</a></h2><h3 id="preguntas-frecuentes-¿que-hacer-si-las-tablas-no-se-formatean" tabindex="-1"><a href="./troubleshooting/">Preguntas Frecuentes: ¿Qué hacer si las tablas no se formatean</a> <a class="header-anchor" href="#preguntas-frecuentes-¿que-hacer-si-las-tablas-no-se-formatean" aria-label="Permalink to &quot;[Preguntas Frecuentes: ¿Qué hacer si las tablas no se formatean](troubleshooting/)&quot;">​</a></h3><p>Presentación completa de los problemas comunes y soluciones en el uso del plugin:</p><ul><li><strong>Tablas no formateadas</strong>: Verificar configuración, requisitos de versión, reiniciar OpenCode</li><li><strong>Estructura de tabla inválida</strong>: Comprender el significado del error &quot;invalid structure&quot;, aprender la sintaxis correcta de tablas</li><li><strong>Fallo en el formateo</strong>: Manejar el error &quot;table formatting failed&quot; y situaciones anormales</li><li><strong>Tipos de tablas no compatibles</strong>: Conocer las limitaciones de las tablas HTML, celdas multilínea, etc.</li><li><strong>Desalineación después del formateo</strong>: Investigar problemas como modo oculto, celdas demasiado largas, código en línea, etc.</li></ul><hr><h2 id="recomendaciones-de-ruta-de-aprendizaje" tabindex="-1">Recomendaciones de Ruta de Aprendizaje <a class="header-anchor" href="#recomendaciones-de-ruta-de-aprendizaje" aria-label="Permalink to &quot;Recomendaciones de Ruta de Aprendizaje&quot;">​</a></h2><p>Se recomienda consultar este capítulo cuando encuentres problemas reales después de completar <a href="./../start/features/">Visión General de Funciones</a>, o usarlo como manual de referencia para la solución de problemas.</p><p>Puedes seguir el siguiente orden de aprendizaje:</p><ol><li><strong>Cuando encuentres problemas</strong>: Primero identifica el tipo de problema según los síntomas (tablas no formateadas, mensajes de error, etc.)</li><li><strong>Investigar paso a paso</strong>: Verifica uno por uno según la lista de verificación de la guía de solución de problemas</li><li><strong>Comprensión profunda</strong>: Lee <a href="./../advanced/table-spec/">Especificaciones de Tablas</a> y <a href="./../advanced/concealment-mode/">Principios del Modo Oculto</a> para conocer los detalles técnicos</li><li><strong>Limitaciones conocidas</strong>: Consulta <a href="./../appendix/limitations/">Limitaciones Conocidas</a> para conocer los límites del plugin</li></ol><hr><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><p>Antes de estudiar este capítulo, se recomienda completar primero:</p><ul><li>✅ <a href="./../start/getting-started/">Comenzar en un Minuto: Instalación y Configuración</a> - Conocer cómo instalar y configurar el plugin</li><li>✅ <a href="./../start/features/">Visión General de Funciones: La Magia del Formateo Automático</a> - Comprender las funciones principales y el principio de funcionamiento del plugin</li></ul><p>Además, deberías tener:</p><ul><li>Familiaridad con la sintaxis básica de tablas Markdown</li><li>Conocimiento del método de configuración de plugins de OpenCode (<code>opencode.jsonc</code>)</li></ul><hr><h2 id="proximos-pasos" tabindex="-1">Próximos Pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos Pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar aprendiendo:</p><ul><li><p><strong>Conocimientos Avanzados</strong>:</p><ul><li><a href="./../advanced/table-spec/">Especificaciones de Tablas: Qué tablas pueden ser formateadas</a> - Dominar los requisitos de estructura de tablas válidas</li><li><a href="./../advanced/concealment-mode/">Principios del Modo Oculto: Por qué el cálculo de ancho es tan importante</a> - Comprender el principio de funcionamiento del modo oculto de OpenCode</li><li><a href="./../advanced/alignment/">Explicación de Alineación: Izquierda, Centro, Derecha</a> - Dominar la sintaxis y los efectos de los tres métodos de alineación</li></ul></li><li><p><strong>Detalles Técnicos</strong>:</p><ul><li><a href="./../appendix/limitations/">Limitaciones Conocidas: ¿Dónde están los límites del plugin</a> - Conocer las limitaciones conocidas y los escenarios no aplicables del plugin</li><li><a href="./../appendix/tech-details/">Detalles Técnicos: Mecanismo de Caché y Optimización de Rendimiento</a> - Conocer el mecanismo de caché interno y las estrategias de optimización de rendimiento del plugin</li></ul></li></ul><hr>',24)])])}const f=a(s,[["render",r]]);export{m as __pageData,f as default};
